import json

def evaluate_response(new_response, existing_responses):
    task_payload = json.loads(json.loads('{{json task}}')['taskPayload'])
    if 'classification' not in new_response:
        return {
            'isValid': False,
            'verification': '',
            'rank': 1,
            'explanation': "New response does not answer the question."
        }

    existing_classification_count = sum(1 for existing_response in existing_responses 
                                         if existing_response['classification'] == task_payload['classification'])

    if new_response['classification'] != task_payload['classification']:
        return {
            'isValid': False,
            'verification': '',
            'rank': 2,
            'explanation': "New response does not address the asked classification type."
        }

    # Check that the answer is related to the question and matches one of the existing classes.

    if not any(is_classification_match(existing_response, new_response) for existing_response in existing_responses):
        return {
            'isValid': False,
            'verification': '',
            'rank': 2,
            'explanation': "New response doesn't align with options provided."
        }

    # Check the task instructions and answer format:

    allowed_classification = ['Linear', 'Quadratic','Exponential']

    if new_response['classification'] not in allowed_classification:
        return {
            'isValid': False,
            'verification': '',
            'rank': 3,
            'explanation': "New response doesn't adhere to task's given options."
        }

    # Rank the new response according to its clarity, correctness, and relevance.

    new_rank = 9
    if existing_classification_count > 0:
      new_rank += 1

    return {
        'isValid': True,
        'verification': json.dumps(task_payload),
        'rank': min(new_rank,10),
        'explanation': f"New response classification is {new_response['classification']}. Scored {min(new_rank,10)}. There were {existing_classification_count} existing answers with same type."
    }

def is_classification_match(existing_response, new_response):
    return existing_response["classification"] ==  (new_response["classification"])


