        'task': {'classification':'Exponential'},
      'answer': {"classification":"Exponential", "comment":""},
        "taskPayload":"{\n\"task\": {\n \"classification\": \"Exponential\"\ntitle\": \"Classify the following equations:\",\n  \"description\":\" Classify the following equations based on their type.\",\n    \"constraints\": [],\n    \"options\": \\\n      [ \\"Linear\\" , \\\n        \"Quadratic\\" , \\\n        \\"Exponential\\" , \\\n       \\"Trigonometric\\" ],\n  \"taskType\": \"classification\"\n}\n}"

   }
   ''',
  "json": json.dumps({
        'answer': {
          "classification":"Exponential"
        },
        "response": {
            "classification": 'Exponential'},
            "comment":""},
       "json"))

existing_responses = [
